               <img alt="" class="wide-image" data-attrs='{"src":"https://bucketeer-e05bbc84-baa3-437e-9518-adb32be77984.s3.amazonaws.com/public/images/3e2fe61d-9354-4c3a-a232-648034dae423_1200x600.png","fullscreen":null,"imageSize":null,"height":600,"width":1200,"resizeWidth":null,"bytes":297941,"alt":null,"title":null,"type":"image/png","href":null}' height="275" src="https://cdn.substack.com/image/fetch/w_2400,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fbucketeer-e05bbc84-baa3-437e-9518-adb32be77984.s3.amazonaws.com%2Fpublic%2Fimages%2F3e2fe61d-9354-4c3a-a232-648034dae423_1200x600.png" style="-ms-interpolation-mode: bicubic; border: none !important; display: block; height: auto; margin: 0 auto; margin-bottom: 0; max-width: 100% !important; vertical-align: middle; width: auto !important;" width="550"/>
